// Feature Engineering Node
// Input 0 = Merge Supplier Data
// Input 1 = Sales History

const today = new Date();
const MS_PER_DAY = 86400000;

// Ensure inputs exist
const inventoryItems = $input.all(0) || [];
const salesItems = $input.all(1) || [];

if (inventoryItems.length === 0) {
  return [];
}

// Convert sales rows
const salesRaw = salesItems.map(i => i.json);

// ---------- Helper Functions ----------

function getDaysSince(dateStr) {
  if (!dateStr) return 9999;
  return (today - new Date(dateStr)) / MS_PER_DAY;
}

function groupSalesBySku(rows) {
  const map = {};

  for (const row of rows) {
    const sku = row.SKU;
    if (!sku) continue;

    if (!map[sku]) map[sku] = [];

    map[sku].push({
      date: row.Date,
      units: Number(row.Units_Sold) || 0
    });
  }

  return map;
}

function calcVelocity(sales, days) {
  const cutoff = new Date(today - days * MS_PER_DAY);

  const filtered = sales.filter(s => new Date(s.date) >= cutoff);

  const total = filtered.reduce((sum, s) => sum + s.units, 0);

  return Number((total / days).toFixed(4));
}

function calcSeasonalityIndex(sales) {
  const now = today.getTime();
  const d30 = now - 30 * MS_PER_DAY;
  const d60 = now - 60 * MS_PER_DAY;

  const recent = sales.filter(s => new Date(s.date).getTime() >= d30);
  const prior = sales.filter(s => {
    const t = new Date(s.date).getTime();
    return t >= d60 && t < d30;
  });

  const recentTotal = recent.reduce((s,x)=>s+x.units,0);
  const priorTotal = prior.reduce((s,x)=>s+x.units,0);

  const recentAvg = recentTotal / 30;
  const priorAvg = priorTotal / 30;

  return priorAvg > 0 ? Number((recentAvg / priorAvg).toFixed(4)) : 1;
}

// ---------- Prepare Sales Map ----------

const salesBySku = groupSalesBySku(salesRaw);

// ---------- Feature Engineering ----------

const enriched = inventoryItems.map(item => {

  const inv = item.json;
  const sku = inv.SKU;

  const sales = salesBySku[sku] || [];

  const currentStock = Number(inv.Current_Stock) || 0;
  const leadTime = Number(inv.Lead_Time_Days) || 7;

  const velocity7 = calcVelocity(sales, 7);
  const velocity30 = calcVelocity(sales, 30);
  const seasonIdx = calcSeasonalityIndex(sales);

  const daysRemaining =
    velocity7 > 0
      ? Number((currentStock / velocity7).toFixed(1))
      : 9999;

  const sales90 = sales
    .filter(s => getDaysSince(s.date) <= 90)
    .sort((a,b)=>new Date(a.date)-new Date(b.date));

  return {
    json: {
      SKU: sku,
      Current_Stock: currentStock,
      Reorder_Point: Number(inv.Reorder_Point) || 0,
      Supplier_ID: inv.Supplier_ID,
      Supplier_Name: inv.Supplier_Name,
      Supplier_Email: inv.Supplier_Email,
      Minimum_Order_Qty: Number(inv.Minimum_Order_Qty) || 0,
      Lead_Time_Days: leadTime,
      Unit_Cost: Number(inv.Unit_Cost) || 0,
      sales_velocity_7_day: velocity7,
      sales_velocity_30_day: velocity30,
      seasonality_index: seasonIdx,
      days_of_inventory_remaining: daysRemaining,
      sales_history_90d: sales90,
      is_critical: currentStock === 0 || daysRemaining < leadTime
    }
  };

});

return enriched;

// Node: AI Response Parser — JavaScript Code Node
// Handles markdown fences, partial JSON, and missing fields

const items = $input.all();

function safeParseJSON(text) {

  let cleaned = (text || "")
    .replace(/```json\n?/g, "")
    .replace(/```\n?/g, "")
    .trim();

  const match = cleaned.match(/\{[\s\S]*\}/);

  if (!match) return null;

  try {
    return JSON.parse(match[0]);
  } catch {

    const fixedJson = match[0].replace(/,\s*([}\]])/g, "$1");

    try {
      return JSON.parse(fixedJson);
    } catch {
      return null;
    }
  }
}

const results = items.map((item, index) => {

  const rawResponse =
      item.json.choices?.[0]?.message?.content
      || item.json.content?.[0]?.text
      || item.json.output
      || "";

  const feData = $items("Merge Supplier Data")[index]?.json || {};

  const sku = feData.SKU || "UNKNOWN";

  const parsed = safeParseJSON(rawResponse);

  const defaults = {
    SKU: sku,
    forecast_14_days: Math.round((feData.sales_velocity_30_day || 0) * 14),
    forecast_30_days: Math.round((feData.sales_velocity_30_day || 0) * 30),
    confidence_score: 0.5,
    seasonality_flag: false,
    trend_direction: "stable",
    reorder_urgency: "medium",
    reasoning: "Fallback: AI response parse failed, using velocity-based estimate",
    parse_failed: true
  };

  const result = parsed ? {
    SKU: parsed.SKU || sku,
    forecast_14_days: parseInt(parsed.forecast_14_days) || defaults.forecast_14_days,
    forecast_30_days: parseInt(parsed.forecast_30_days) || defaults.forecast_30_days,
    confidence_score: parseFloat(parsed.confidence_score) || defaults.confidence_score,
    seasonality_flag: Boolean(parsed.seasonality_flag),
    trend_direction: parsed.trend_direction || defaults.trend_direction,
    reorder_urgency: parsed.reorder_urgency || defaults.reorder_urgency,
    reasoning: parsed.reasoning || "",
    parse_failed: false
  } : defaults;

  return {
    json: {
      ...feData,
      ...result,
      forecast_generated_at: new Date().toISOString()
    }
  };
});

return results;

// Node: Purchase Order Generator — JavaScript Code Node

function generatePOId(sku) {
  const date = new Date().toISOString().slice(0,10).replace(/-/g,"");
  const random = Math.random().toString(36).substring(2,8).toUpperCase();
  return `PO-${date}-${random}`;
}

function generateToken() {
  return Math.random().toString(36).substring(2) +
         Math.random().toString(36).substring(2);
}

function calcExpectedDelivery(leadTimeDays) {
  const d = new Date();
  d.setDate(d.getDate() + (leadTimeDays || 7) + 1);
  return d.toISOString().slice(0,10);
}

return $input.all()
  .filter(item => item.json.needs_reorder)
  .map(item => {

    const d = item.json;

    const qty = Number(d.optimal_reorder_qty) || 0;
    const unitCost = Number(d.Unit_Cost) || 0;

    return {
      json: {

        PO_ID: generatePOId(d.SKU),

        SKU: d.SKU,

        Supplier_ID: d.Supplier_ID,

        Supplier_Name: d.Supplier_Name,

        Supplier_Email: d.Supplier_Email,

        Quantity: qty,

        Unit_Cost: unitCost,

        Estimated_Total_Cost: unitCost ? unitCost * qty : null,

        Expected_Delivery_Date: calcExpectedDelivery(d.Lead_Time_Days),

        Lead_Time_Days: d.Lead_Time_Days,

        Current_Stock: d.Current_Stock,

        Reorder_Point: d.Reorder_Point,

        Forecast_14_Days: d.forecast_14_days,

        Forecast_30_Days: d.forecast_30_days,

        Confidence_Score: d.confidence_score,

        Reorder_Urgency: d.reorder_urgency,

        Is_Critical: d.is_critical,

        Status: "PENDING_APPROVAL",

        Created_At: new Date().toISOString(),

        Approval_Token: generateToken()

      }
    };

});

