const SAFETY_STOCK_MULTIPLIER = 1.25;
const MIN_SAFETY_STOCK_DAYS = 5;

return $input.all().map(item => {

  const d = item.json;

  const forecast30 = Number(d.forecast_30_days) || 0;
  const leadTime = Number(d.Lead_Time_Days) || 7;
  const currentStock = Number(d.Current_Stock) || 0;
  const reorderPoint = Number(d.Reorder_Point) || 0;
  const velocity7 = Number(d.sales_velocity_7_day) || 0;
  const supplierMinQty = Number(d.Minimum_Order_Qty) || 1;

  const dailyDemand = forecast30 / 30;

  const leadTimeDemand = dailyDemand * leadTime;

  const safetyStock = Math.max(
    leadTimeDemand * (SAFETY_STOCK_MULTIPLIER - 1),
    velocity7 * MIN_SAFETY_STOCK_DAYS
  );

  let rawQty = leadTimeDemand + safetyStock - currentStock;

  // fallback when forecast is zero
  if (forecast30 === 0 && currentStock <= reorderPoint) {
    rawQty = reorderPoint - currentStock;
  }

  let reorder_qty = Math.max(
    supplierMinQty,
    Math.ceil(rawQty / supplierMinQty) * supplierMinQty
  );

  if (rawQty <= 0) reorder_qty = 0;

  const isCritical =
    currentStock === 0 || d.reorder_urgency === "critical";

  const needsReorder =
    currentStock <= reorderPoint || isCritical;

  return {
    json: {
      ...d,
      daily_demand_forecast: Number(dailyDemand.toFixed(4)),
      lead_time_demand: Number(leadTimeDemand.toFixed(2)),
      safety_stock: Number(safetyStock.toFixed(2)),
      optimal_reorder_qty: reorder_qty,
      needs_reorder: needsReorder,
      is_critical: isCritical,
      reorder_trigger: needsReorder
        ? (isCritical ? "True" : "false")
        : "NONE"
    }
  };

});
